    // Register an event listener for later cleanup
    addTrackedListener(element, event, handler, options) {
        if (element) {
            element.addEventListener(event, handler, options);
            this._eventListeners.push({ element, event, handler, options });
        }
    },
    
    // Track interval for cleanup
    addTrackedInterval(id) {
        this._intervals.push(id);
        return id;
    },
    
    // Track timeout for cleanup
    addTrackedTimeout(id) {
        this._timeouts.push(id);
        return id;
    },
    
    // Remove all tracked event listeners (call on cleanup)
    removeAllListeners() {
        this._eventListeners.forEach(({ element, event, handler, options }) => {
            if (element) {
                element.removeEventListener(event, handler, options);
            }
        });
        this._eventListeners = [];
    },
    
    // Clear all intervals
    clearAllIntervals() {
        this._intervals.forEach(id => clearInterval(id));
        this._intervals = [];
    },
    
    // Clear all timeouts  
    clearAllTimeouts() {
        this._timeouts.forEach(id => clearTimeout(id));
        this._timeouts = [];
    },
    
    // Full cleanup - call on page unload
    cleanup() {
        this.removeAllListeners();
        this.clearAllIntervals();
        this.clearAllTimeouts();
    },
    
    // Debug-safe logging wrapper
    log(...args) { if (this.DEBUG) console.log('[FCC]', ...args); },
    warn(...args) { if (this.DEBUG) console.warn('[FCC]', ...args); },
    error(...args) { if (this.DEBUG) console.error('[FCC]', ...args); },

    // HTML sanitization to prevent XSS
    sanitize(str) {
        if (str === null || str === undefined) return '';
        const div = document.createElement('div');
        div.textContent = String(str);
        return div.innerHTML;
    },

    // Submit debounce guard to prevent duplicate submissions
    _submitting: false,
    guardSubmit(fn) {
        if (this._submitting) return;
        this._submitting = true;
        try { fn(); } finally {
            setTimeout(() => { this._submitting = false; }, 500);
        }
    },
    
