    // Haptic feedback for touch interactions
    haptic(type = 'light') {
        if (!navigator.vibrate) return;
        const patterns = {
            light: 10,
            medium: 25,
            heavy: 50,
            success: [10, 50, 20],
            error: [50, 30, 50, 30, 50],
            warning: [30, 20, 30]
        };
        navigator.vibrate(patterns[type] || patterns.light);
    },
    
    // Loading state management
    _loadingStates: new Set(),
    
    showLoading(id = 'global', message = 'Loading...') {
        this._loadingStates.add(id);
        let overlay = document.getElementById('loading-overlay');
        if (!overlay) {
            overlay = document.createElement('div');
            overlay.id = 'loading-overlay';
            overlay.className = 'loading-overlay';
            overlay.innerHTML = `
                <div class="loading-spinner"></div>
                <div class="loading-message" id="loading-message">${message}</div>
            `;
            document.body.appendChild(overlay);
        } else {
            document.getElementById('loading-message').textContent = message;
        }
        overlay.classList.add('visible');
    },
    
    hideLoading(id = 'global') {
        this._loadingStates.delete(id);
        if (this._loadingStates.size === 0) {
            const overlay = document.getElementById('loading-overlay');
            if (overlay) overlay.classList.remove('visible');
        }
    },
    
    // Button loading state
    setButtonLoading(btn, loading = true) {
        if (!btn) return;
        if (loading) {
            btn.dataset.originalText = btn.innerHTML;
            btn.innerHTML = '<span class="btn-spinner"></span>';
            btn.disabled = true;
        } else {
            btn.innerHTML = btn.dataset.originalText || btn.innerHTML;
            btn.disabled = false;
        }
    },
    
