    // Check if prices are stale and refresh automatically
    async autoRefreshIfStale() {
        const lastUpdate = this.data.lastPriceUpdate;
        const oneHour = 60 * 60 * 1000;
        const isStale = !lastUpdate || (Date.now() - new Date(lastUpdate).getTime()) > oneHour;
        
        if (isStale) {
            
            // Delay slightly to let UI render first
            setTimeout(async () => {
                try {
                    await this.refreshAll();
                } catch (e) {
                    
                    this.markPricesAsStale();
                }
            }, 1500);
        } else {
            
        }
    },
    
    // Mark prices as stale with visual indicator
    markPricesAsStale() {
        const timestamp = document.getElementById('timestamp');
        if (timestamp) {
            timestamp.innerHTML += ' <span style="color:var(--accent-amber);font-size:10px">(Prices may be outdated)</span>';
        }
    },
    
