    initLiveIndicators() {
        // Add live pulse to elements showing live data
        const liveElements = document.querySelectorAll('.price-live, .fx-live');
        liveElements.forEach(el => {
            el.classList.add('live-indicator');
        });
    },
    
    initScrollAnimations() {
        // Animate elements as they scroll into view
        if ('IntersectionObserver' in window) {
            const observer = new IntersectionObserver((entries) => {
                entries.forEach(entry => {
                    if (entry.isIntersecting) {
                        entry.target.classList.add('animate');
                        observer.unobserve(entry.target);
                    }
                });
            }, { threshold: 0.1 });
            
            document.querySelectorAll('.section, .card').forEach(el => {
                el.classList.add('stagger-enter');
                observer.observe(el);
            });
        }
    },
    
    initValueChangeDetection() {
        // Store previous values to detect changes
        this._previousValues = {
            netWorth: this.calcNetWorth(),
            crypto: this.calcCrypto().value,
            equity: this.calcEquity().value
        };
    },
    
    // Animate value changes
    animateValueChange(elementId, newValue, oldValue) {
        const el = document.getElementById(elementId);
        if (!el) return;
        
        // Add scale animation
        el.classList.add('animate-value', 'updating');
        
        // Determine direction and add appropriate class
        if (newValue > oldValue) {
            el.classList.add('value-up');
            el.classList.add('glow-green');
            setTimeout(() => {
                el.classList.remove('value-up', 'glow-green', 'updating');
            }, 800);
        } else if (newValue < oldValue) {
            el.classList.add('value-down');
            el.classList.add('glow-red');
            setTimeout(() => {
                el.classList.remove('value-down', 'glow-red', 'updating');
            }, 800);
        } else {
            setTimeout(() => el.classList.remove('updating'), 300);
        }
    },
    
    // Smooth number counting animation
    animateNumber(elementId, targetValue, duration = 800, formatter = null) {
        const el = document.getElementById(elementId);
        if (!el) return;
        
        // Get current displayed value (parse number from text)
        const currentText = el.textContent.replace(/[^0-9.-]/g, '');
        const startValue = parseFloat(currentText) || 0;
        
        // Don't animate if values are the same
        if (Math.abs(targetValue - startValue) < 0.01) return;
        
        const startTime = performance.now();
        const diff = targetValue - startValue;
        
        // Use requestAnimationFrame for smooth animation
        const animate = (currentTime) => {
            const elapsed = currentTime - startTime;
            const progress = Math.min(elapsed / duration, 1);
            
            // Easing function (ease-out cubic)
            const eased = 1 - Math.pow(1 - progress, 3);
            
            const currentValue = startValue + (diff * eased);
            
            // Format the value
            if (formatter) {
                el.textContent = formatter(currentValue);
            } else {
                el.textContent = this.fmtFull(currentValue);
            }
            
            if (progress < 1) {
                requestAnimationFrame(animate);
            }
        };
        
        requestAnimationFrame(animate);
    },
    
    // Animate hero values with counting effect
    animateHeroValues(netWorth, assets, liabilities) {
        // Only animate if values have changed significantly
        const threshold = 10; // Min change to trigger animation
        
        const currentNW = parseFloat((document.getElementById('hero-net-worth')?.textContent || '0').replace(/[^0-9.-]/g, '')) || 0;
        
        if (Math.abs(netWorth - currentNW) > threshold) {
            this.animateNumber('hero-net-worth', netWorth, 600);
        }
    },
    
