    // Trigger confetti animation (for achievements/milestones)
    triggerConfetti() {
        const colors = ['#00ff88', '#FF6B00', '#4488ff', '#aa66ff', '#ffaa00'];
        const container = document.createElement('div');
        container.style.cssText = 'position:fixed;top:50%;left:50%;pointer-events:none;z-index:9999;';
        document.body.appendChild(container);
        
        for (let i = 0; i < 30; i++) {
            const particle = document.createElement('div');
            particle.className = 'confetti-particle';
            particle.style.cssText = `
                background: ${colors[Math.floor(Math.random() * colors.length)]};
                left: ${Math.random() * 100 - 50}px;
                animation-delay: ${Math.random() * 0.3}s;
                animation-duration: ${0.8 + Math.random() * 0.4}s;
            `;
            container.appendChild(particle);
        }
        
        setTimeout(() => container.remove(), 1500);
    },
    
