// BENCHMARK COMPARISON MODULE
// ═══════════════════════════════════════════════════════════════════════════

Object.assign(App, {
    
    benchmarks: [
        { id: 'sp500', name: 'S&P 500', symbol: '^GSPC', icon: '🇺🇸', ytd: 12.5, oneYear: 18.2, threeYear: 32.1 },
        { id: 'ftse100', name: 'FTSE 100', symbol: '^FTSE', icon: '🇬🇧', ytd: 4.2, oneYear: 8.5, threeYear: 15.3 },
        { id: 'btc', name: 'Bitcoin', symbol: 'BTC', icon: '₿', ytd: 45.2, oneYear: 85.3, threeYear: 120.5 },
        { id: 'gold', name: 'Gold', symbol: 'GLD', icon: '🥇', ytd: 8.1, oneYear: 12.4, threeYear: 28.6 }
    ],
    
    // UK Wealth percentiles by age (approximate median values)
    ukWealthData: {
        '25-34': { median: 15000, p75: 75000, p90: 200000, p95: 350000 },
        '35-44': { median: 75000, p75: 200000, p90: 450000, p95: 750000 },
        '45-54': { median: 150000, p75: 350000, p90: 700000, p95: 1100000 },
        '55-64': { median: 250000, p75: 500000, p90: 950000, p95: 1500000 },
        '65+': { median: 300000, p75: 550000, p90: 1000000, p95: 1700000 }
    },
    
    renderBenchmark() {
        this.renderBenchmarkGrid();
        this.renderWealthPercentile();
        this.renderPerformanceMetrics();
    },
    
    renderBenchmarkGrid() {
        const container = document.getElementById('benchmark-grid');
        if (!container) return;
        
        // Calculate portfolio YTD return (simplified)
        const nw = this.calcNetWorth();
        const portfolioYTD = 15.5; // Placeholder - would need historical data
        const portfolioOneYear = 25.3;
        const portfolioThreeYear = 85.2;
        
        container.innerHTML = this.benchmarks.map(b => {
            const diffYTD = portfolioYTD - b.ytd;
            const diffClass = diffYTD >= 0 ? 'positive' : 'negative';
            
            return `<div class="benchmark-card">
                <div class="benchmark-header">
                    <div class="benchmark-icon">${b.icon}</div>
                    <div>
                        <div class="benchmark-name">${b.name}</div>
                        <div class="benchmark-period">vs Your Portfolio</div>
                    </div>
                </div>
                <div class="benchmark-comparison">
                    <div>
                        <div style="font-size:11px;color:var(--text-muted)">YTD</div>
                        <div class="benchmark-value">${b.ytd > 0 ? '+' : ''}${b.ytd}%</div>
                    </div>
                    <span class="benchmark-diff ${diffClass}">${diffYTD >= 0 ? '+' : ''}${diffYTD.toFixed(1)}%</span>
                </div>
                <div class="benchmark-comparison">
                    <div>
                        <div style="font-size:11px;color:var(--text-muted)">1 Year</div>
                        <div class="benchmark-value">${b.oneYear > 0 ? '+' : ''}${b.oneYear}%</div>
                    </div>
                    <span class="benchmark-diff ${portfolioOneYear - b.oneYear >= 0 ? 'positive' : 'negative'}">${portfolioOneYear - b.oneYear >= 0 ? '+' : ''}${(portfolioOneYear - b.oneYear).toFixed(1)}%</span>
                </div>
            </div>`;
        }).join('');
    },
    
    renderWealthPercentile() {
        const nw = this.calcNetWorth();
        const age = this.fireInputs?.age || 35;
        
        // Determine age bracket
        let bracket;
        if (age < 35) bracket = '25-34';
        else if (age < 45) bracket = '35-44';
        else if (age < 55) bracket = '45-54';
        else if (age < 65) bracket = '55-64';
        else bracket = '65+';
        
        const data = this.ukWealthData[bracket];
        
        let percentile;
        if (nw >= data.p95) percentile = 'Top 5%';
        else if (nw >= data.p90) percentile = 'Top 10%';
        else if (nw >= data.p75) percentile = 'Top 25%';
        else if (nw >= data.median) percentile = 'Top 50%';
        else percentile = 'Below Median';
        
        this.setText('wealth-percentile', percentile);
        this.setText('median-nw', this.fmt(data.median));
        this.setText('vs-median', (nw >= data.median ? '+' : '') + this.fmt(nw - data.median));
    },
    
    renderPerformanceMetrics() {
        // Simplified metrics - would need historical data for accuracy
        const volatility = 18.5; // Placeholder
        const riskFreeRate = 4.5; // Current approx
        const portfolioReturn = 15.5;
        const sharpe = (portfolioReturn - riskFreeRate) / volatility;
        
        this.setText('sharpe-ratio', sharpe.toFixed(2));
        this.setText('portfolio-volatility', volatility.toFixed(1) + '%');
        this.setText('max-drawdown', '-32.4%'); // Placeholder
        this.setText('portfolio-beta', '1.15'); // Placeholder
    }
});

