// RECURRING TRANSACTIONS MODULE
// ═══════════════════════════════════════════════════════════════════════════

Object.assign(App, {
    
    defaultRecurring: [
        { id: 1, name: 'Salary', type: 'income', amount: 5000, frequency: 'monthly', day: 28, icon: '💼', active: true },
        { id: 2, name: 'ADA Staking', type: 'income', amount: 150, frequency: 'monthly', day: 1, icon: '●', active: true },
        { id: 3, name: 'Tesla Finance', type: 'expense', amount: 774, frequency: 'monthly', day: 15, icon: '🚗', active: true },
        { id: 4, name: 'Mortgage', type: 'expense', amount: 1200, frequency: 'monthly', day: 1, icon: '🏠', active: true },
        { id: 5, name: 'Utilities', type: 'expense', amount: 180, frequency: 'monthly', day: 5, icon: '⚡', active: true },
        { id: 6, name: 'Phone & Internet', type: 'expense', amount: 85, frequency: 'monthly', day: 10, icon: '◱', active: true }
    ],
    
    initRecurring() {
        if (!this.data.recurring) {
            this.data.recurring = [...this.defaultRecurring];
        }
    },
    
    renderRecurring() {
        this.initRecurring();
        this.renderRecurringSummary();
        this.renderRecurringGrids();
        this.renderUpcoming();
    },
    
    renderRecurringSummary() {
        const items = this.data.recurring.filter(r => r.active);
        
        let monthlyIncome = 0, monthlyExpense = 0;
        items.forEach(r => {
            const monthly = r.frequency === 'monthly' ? r.amount : 
                           r.frequency === 'weekly' ? r.amount * 4.33 :
                           r.frequency === 'yearly' ? r.amount / 12 : r.amount;
            
            if (r.type === 'income') monthlyIncome += monthly;
            else monthlyExpense += monthly;
        });
        
        this.setText('recurring-income', this.fmt(monthlyIncome));
        this.setText('recurring-expenses', this.fmt(monthlyExpense));
        this.setText('recurring-net', (monthlyIncome - monthlyExpense >= 0 ? '+' : '') + this.fmt(monthlyIncome - monthlyExpense));
        this.setText('recurring-count', items.length);
        
        const netEl = document.getElementById('recurring-net');
        if (netEl) netEl.style.color = monthlyIncome >= monthlyExpense ? 'var(--accent-green)' : 'var(--accent-red)';
    },
    
    renderRecurringGrids() {
        const incomeGrid = document.getElementById('recurring-income-grid');
        const expenseGrid = document.getElementById('recurring-expense-grid');
        
        if (incomeGrid) {
            const incomes = this.data.recurring.filter(r => r.type === 'income');
            incomeGrid.innerHTML = incomes.length === 0 ? 
                '<p style="color:var(--text-muted);text-align:center;padding:20px">No recurring income</p>' :
                incomes.map(r => this.renderRecurringCard(r)).join('');
        }
        
        if (expenseGrid) {
            const expenses = this.data.recurring.filter(r => r.type === 'expense');
            expenseGrid.innerHTML = expenses.length === 0 ?
                '<p style="color:var(--text-muted);text-align:center;padding:20px">No recurring expenses</p>' :
                expenses.map(r => this.renderRecurringCard(r)).join('');
        }
    },
    
    renderRecurringCard(r) {
        const nextDate = this.getNextOccurrence(r);
        return `<div class="recurring-card ${r.active ? '' : 'opacity-50'}">
            <div class="recurring-header">
                <div style="display:flex;align-items:center;gap:12px">
                    <div class="recurring-icon ${r.type}">${r.icon}</div>
                    <div>
                        <div class="recurring-name">${r.name}</div>
                        <div class="recurring-schedule">${r.frequency}${r.day ? ' (day ' + r.day + ')' : ''}</div>
                    </div>
                </div>
                <div class="recurring-amount ${r.type}">${r.type === 'income' ? '+' : '-'}${this.fmt(r.amount)}</div>
            </div>
            <div class="recurring-next">
                <span class="recurring-next-label">Next: <span class="recurring-next-date">${nextDate}</span></span>
                <div class="recurring-toggle ${r.active ? 'active' : ''}" onclick="App.toggleRecurring(${r.id})"></div>
            </div>
            <div class="action-btns mt-1">
                <button class="action-btn" onclick="App.editRecurring(${r.id})">Edit</button>
                <button class="action-btn delete" onclick="App.deleteRecurring(${r.id})">Delete</button>
            </div>
        </div>`;
    },
    
    getNextOccurrence(r) {
        const now = new Date();
        const day = r.day || 1;
        let next = new Date(now.getFullYear(), now.getMonth(), day);
        
        if (next <= now) {
            if (r.frequency === 'monthly') next.setMonth(next.getMonth() + 1);
            else if (r.frequency === 'weekly') next.setDate(next.getDate() + 7);
            else if (r.frequency === 'yearly') next.setFullYear(next.getFullYear() + 1);
        }
        
        return next.toLocaleDateString('en-GB', { day: 'numeric', month: 'short' });
    },
    
    renderUpcoming() {
        const container = document.getElementById('recurring-upcoming');
        if (!container) return;
        
        const now = new Date();
        const endOfMonth = new Date(now.getFullYear(), now.getMonth() + 1, 0);
        
        const upcoming = this.data.recurring
            .filter(r => r.active)
            .map(r => {
                const day = r.day || 1;
                let date = new Date(now.getFullYear(), now.getMonth(), day);
                if (date < now) date.setMonth(date.getMonth() + 1);
                return { ...r, nextDate: date };
            })
            .filter(r => r.nextDate <= endOfMonth)
            .sort((a, b) => a.nextDate - b.nextDate);
        
        if (upcoming.length === 0) {
            container.innerHTML = '<p style="color:var(--text-muted);text-align:center;padding:20px">No upcoming transactions this month</p>';
            return;
        }
        
        container.innerHTML = `<div class="income-sources">${upcoming.map(r => `
            <div class="income-item">
                <div class="income-icon">${r.icon}</div>
                <div class="income-info">
                    <div class="income-name">${r.name}</div>
                    <div class="income-freq">${r.nextDate.toLocaleDateString('en-GB', { weekday: 'short', day: 'numeric', month: 'short' })}</div>
                </div>
                <div class="income-amount" style="color:${r.type === 'income' ? 'var(--accent-green)' : 'var(--accent-red)'}">${r.type === 'income' ? '+' : '-'}${this.fmt(r.amount)}</div>
            </div>
        `).join('')}</div>`;
    },
    
    showAddBudgetRecurringModal(type) {
        const body = `
            <div class="form-group"><label class="form-label">Name</label><input type="text" class="form-input" id="rec-name" placeholder="e.g., Salary, Rent"></div>
            <div class="form-group"><label class="form-label">Amount (£)</label><input type="number" class="form-input" id="rec-amount" step="any" placeholder="0"></div>
            <div class="form-group"><label class="form-label">Frequency</label>
                <select class="form-input" id="rec-frequency">
                    <option value="monthly">Monthly</option>
                    <option value="weekly">Weekly</option>
                    <option value="yearly">Yearly</option>
                </select>
            </div>
            <div class="form-group"><label class="form-label">Day of Month</label><input type="number" class="form-input" id="rec-day" min="1" max="31" value="1"></div>
            <div class="form-group"><label class="form-label">Icon</label>
                <select class="form-input" id="rec-icon">
                    <option value="💼">Salary</option>
                    <option value="●">Crypto</option>
                    <option value="🏠">Housing</option>
                    <option value="🚗">Transport</option>
                    <option value="⚡">Utilities</option>
                    <option value="◱">Phone/Internet</option>
                    <option value="🎬">Subscriptions</option>
                    <option value="💳">Debt Payment</option>
                    <option value="💰">Other</option>
                </select>
            </div>
            <input type="hidden" id="rec-type" value="${type}">
            <button class="btn btn-primary" onclick="App.addBudgetRecurring()" style="width:100%;margin-top:16px">Add ${type === 'income' ? 'Income' : 'Expense'}</button>
        `;
        this.openModal(`Add Recurring ${type === 'income' ? 'Income' : 'Expense'}`, body);
    },
    
    addBudgetRecurring() {
        this.saveUndoState('Add Recurring');
        this.initRecurring();
        
        const name = document.getElementById('rec-name')?.value?.trim();
        const amount = parseFloat(document.getElementById('rec-amount')?.value) || 0;
        const frequency = document.getElementById('rec-frequency')?.value;
        const day = parseInt(document.getElementById('rec-day')?.value) || 1;
        const icon = document.getElementById('rec-icon')?.value;
        const type = document.getElementById('rec-type')?.value;
        
        if (!name || amount <= 0) { this.toast('Please fill in all fields', true); return; }
        
        this.data.recurring.push({ id: Date.now(), name, type, amount, frequency, day, icon, active: true });
        this.save();
        this.closeModal();
        this.renderRecurring();
        this.toast('Recurring item added');
    },
    
    toggleBudgetRecurring(id) {
        const item = this.data.recurring.find(r => r.id === id);
        if (item) {
            item.active = !item.active;
            this.save();
            this.renderRecurring();
        }
    },
    
    deleteBudgetRecurring(id) {
        if (!confirm('Delete this recurring item?')) return;
        this.saveUndoState('Delete Recurring');
        this.data.recurring = this.data.recurring.filter(r => r.id !== id);
        this.save();
        this.renderRecurring();
        this.toast('Recurring item deleted');
    },
    
    editBudgetRecurring(id) {
        const r = this.data.recurring.find(x => x.id === id);
        if (!r) return;
        
        const body = `
            <div class="form-group"><label class="form-label">Name</label><input type="text" class="form-input" id="rec-name" value="${r.name}"></div>
            <div class="form-group"><label class="form-label">Amount (£)</label><input type="number" class="form-input" id="rec-amount" step="any" value="${r.amount}"></div>
            <div class="form-group"><label class="form-label">Frequency</label>
                <select class="form-input" id="rec-frequency">
                    <option value="monthly" ${r.frequency === 'monthly' ? 'selected' : ''}>Monthly</option>
                    <option value="weekly" ${r.frequency === 'weekly' ? 'selected' : ''}>Weekly</option>
                    <option value="yearly" ${r.frequency === 'yearly' ? 'selected' : ''}>Yearly</option>
                </select>
            </div>
            <div class="form-group"><label class="form-label">Day of Month</label><input type="number" class="form-input" id="rec-day" min="1" max="31" value="${r.day || 1}"></div>
            <button class="btn btn-primary" onclick="App.updateBudgetRecurring(${id})" style="width:100%;margin-top:16px">Save Changes</button>
        `;
        this.openModal('✏️ Edit Recurring', body);
    },
    
    updateBudgetRecurring(id) {
        this.saveUndoState('Edit Recurring');
        const r = this.data.recurring.find(x => x.id === id);
        if (!r) return;
        
        r.name = document.getElementById('rec-name')?.value?.trim();
        r.amount = parseFloat(document.getElementById('rec-amount')?.value) || 0;
        r.frequency = document.getElementById('rec-frequency')?.value;
        r.day = parseInt(document.getElementById('rec-day')?.value) || 1;
        
        this.save();
        this.closeModal();
        this.renderRecurring();
        this.toast('Recurring item updated');
    }
});

// ═══════════════════════════════════════════════════════════════════════════
// DOCUMENT VAULT MODULE
// ═══════════════════════════════════════════════════════════════════════════

Object.assign(App, {
    
    vaultFolders: [
        { id: 'statements', name: 'Bank Statements', icon: '■', count: 0 },
        { id: 'loans', name: 'Loan Documents', icon: '▤', count: 0 },
        { id: 'tax', name: 'Tax Returns', icon: '≡', count: 0 },
        { id: 'receipts', name: 'Receipts', icon: '🧾', count: 0 },
        { id: 'insurance', name: 'Insurance', icon: '🛡️', count: 0 },
        { id: 'other', name: 'Other', icon: '▢', count: 0 }
    ],
    
    initVault() {
        if (!this.data.vaultDocuments) {
            this.data.vaultDocuments = [];
        }
    },
    
    renderVault() {
        this.initVault();
        this.renderVaultFolders();
        this.renderRecentDocuments();
        this.updateVaultStats();
        this.initUploadDragDrop();
    },
    
    renderVaultFolders() {
        const container = document.getElementById('vault-folders');
        if (!container) return;
        
        // Count documents per folder
        const docs = this.data.vaultDocuments || [];
        const counts = {};
        docs.forEach(d => counts[d.folder] = (counts[d.folder] || 0) + 1);
        
        container.innerHTML = this.vaultFolders.map(f => `
            <div class="vault-folder" onclick="App.openFolder('${f.id}')">
                <div class="vault-folder-icon">${f.icon}</div>
                <div class="vault-folder-name">${f.name}</div>
                <div class="vault-folder-count">${counts[f.id] || 0} documents</div>
            </div>
        `).join('');
    },
    
    renderRecentDocuments() {
        const container = document.getElementById('vault-recent');
        if (!container) return;
        
        const docs = (this.data.vaultDocuments || []).slice(-5).reverse();
        
        if (docs.length === 0) {
            container.innerHTML = '<p style="color:var(--text-muted);text-align:center;padding:30px">No documents uploaded yet</p>';
            return;
        }
        
        container.innerHTML = docs.map(d => `
            <div class="vault-document">
                <div class="vault-doc-icon">${this.getFileIcon(d.type)}</div>
                <div class="vault-doc-info">
                    <div class="vault-doc-name">${d.name}</div>
                    <div class="vault-doc-meta">${d.folder} • ${this.formatFileSize(d.size)} • ${new Date(d.date).toLocaleDateString('en-GB')}</div>
                </div>
                <button class="btn btn-secondary" style="padding:6px 12px;font-size:11px" onclick="App.downloadDocument(${d.id})">📥</button>
                <button class="btn btn-secondary" style="padding:6px 12px;font-size:11px" onclick="App.deleteDocument(${d.id})">✕</button>
            </div>
        `).join('');
    },
    
    updateVaultStats() {
        const docs = this.data.vaultDocuments || [];
        const totalSize = docs.reduce((s, d) => s + (d.size || 0), 0);
        
        this.setText('vault-doc-count', docs.length);
        this.setText('vault-folder-count', this.vaultFolders.length);
        this.setText('vault-size', this.formatFileSize(totalSize));
    },
    
    getFileIcon(type) {
        if (type?.includes('pdf')) return '📕';
        if (type?.includes('image')) return '🖼️';
        if (type?.includes('sheet') || type?.includes('excel')) return '📊';
        if (type?.includes('doc')) return '▤';
        return '📎';
    },
    
    formatFileSize(bytes) {
        if (bytes < 1024) return bytes + ' B';
        if (bytes < 1048576) return (bytes / 1024).toFixed(1) + ' KB';
        return (bytes / 1048576).toFixed(1) + ' MB';
    },
    
    initUploadDragDrop() {
        const zone = document.getElementById('upload-zone');
        if (!zone) return;
        
        zone.addEventListener('dragover', (e) => {
            e.preventDefault();
            zone.classList.add('dragover');
        });
        
        zone.addEventListener('dragleave', () => {
            zone.classList.remove('dragover');
        });
        
        zone.addEventListener('drop', (e) => {
            e.preventDefault();
            zone.classList.remove('dragover');
            this.handleFileUpload({ target: { files: e.dataTransfer.files } });
        });
    },
    
    showUploadModal() {
        const body = `
            <div class="form-group"><label class="form-label">Folder</label>
                <select class="form-input" id="upload-folder">
                    ${this.vaultFolders.map(f => `<option value="${f.id}">${f.name}</option>`).join('')}
                </select>
            </div>
            <div class="form-group"><label class="form-label">Description (optional)</label><input type="text" class="form-input" id="upload-desc" placeholder="Brief description"></div>
            <div class="vault-upload-zone" onclick="document.getElementById('modal-file-input').click()" style="margin-top:16px">
                <div class="vault-upload-icon">📎</div>
                <div class="vault-upload-text">Click to select files</div>
            </div>
            <input type="file" id="modal-file-input" style="display:none" multiple onchange="App.processModalUpload(event)">
        `;
        this.openModal('Upload Document', body);
    },
    
    handleFileUpload(event) {
        const files = event.target.files;
        if (!files || files.length === 0) return;
        
        this.initVault();
        
        Array.from(files).forEach(file => {
            // Store file metadata (actual file storage would require backend)
            const doc = {
                id: Date.now() + Math.random(),
                name: file.name,
                type: file.type,
                size: file.size,
                folder: 'other',
                date: new Date().toISOString(),
                description: ''
            };
            
            // Auto-categorize based on filename
            const nameLower = file.name.toLowerCase();
            if (nameLower.includes('statement')) doc.folder = 'statements';
            else if (nameLower.includes('loan') || nameLower.includes('mortgage')) doc.folder = 'loans';
            else if (nameLower.includes('tax') || nameLower.includes('hmrc')) doc.folder = 'tax';
            else if (nameLower.includes('receipt')) doc.folder = 'receipts';
            else if (nameLower.includes('insurance')) doc.folder = 'insurance';
            
            this.data.vaultDocuments.push(doc);
        });
        
        this.save();
        this.renderVault();
        this.toast(`${files.length} file(s) uploaded`);
    },
    
    processModalUpload(event) {
        const files = event.target.files;
        const folder = document.getElementById('upload-folder')?.value || 'other';
        const desc = document.getElementById('upload-desc')?.value || '';
        
        if (!files || files.length === 0) return;
        
        this.initVault();
        
        Array.from(files).forEach(file => {
            this.data.vaultDocuments.push({
                id: Date.now() + Math.random(),
                name: file.name,
                type: file.type,
                size: file.size,
                folder: folder,
                date: new Date().toISOString(),
                description: desc
            });
        });
        
        this.save();
        this.closeModal();
        this.renderVault();
        this.toast(`${files.length} file(s) uploaded`);
    },
    
    openFolder(folderId) {
        const folder = this.vaultFolders.find(f => f.id === folderId);
        const docs = (this.data.vaultDocuments || []).filter(d => d.folder === folderId);
        
        let body = `<div style="display:grid;gap:12px">`;
        
        if (docs.length === 0) {
            body += '<p style="color:var(--text-muted);text-align:center;padding:30px">No documents in this folder</p>';
        } else {
            body += docs.map(d => `
                <div class="vault-document">
                    <div class="vault-doc-icon">${this.getFileIcon(d.type)}</div>
                    <div class="vault-doc-info">
                        <div class="vault-doc-name">${d.name}</div>
                        <div class="vault-doc-meta">${this.formatFileSize(d.size)} • ${new Date(d.date).toLocaleDateString('en-GB')}</div>
                    </div>
                    <button class="btn btn-secondary" style="padding:6px 12px;font-size:11px" onclick="App.deleteDocument(${d.id})">✕</button>
                </div>
            `).join('');
        }
        
        body += '</div>';
        this.openModal(`${folder.icon} ${folder.name}`, body);
    },
    
    deleteDocument(id) {
        if (!confirm('Delete this document?')) return;
        this.saveUndoState('Delete Document');
        this.data.vaultDocuments = this.data.vaultDocuments.filter(d => d.id !== id);
        this.save();
        this.renderVault();
        this.closeModal();
        this.toast('Document deleted');
    }
});

// ═══════════════════════════════════════════════════════════════════════════
// ENHANCED AI ASSISTANT MODULE
// ═══════════════════════════════════════════════════════════════════════════

Object.assign(App, {
    
    aiCapabilities: [
        'portfolio analysis', 'debt strategy', 'goal planning', 'tax optimization',
        'rebalancing', 'risk assessment', 'cash flow', 'retirement planning'
    ],
    
    enhancedProcessQuery(query) {
        const q = query.toLowerCase();
        
        // Monte Carlo / Projection queries
        if (q.includes('monte carlo') || q.includes('simulation') || q.includes('project')) {
            if (!this.monteCarloResults) this.runMonteCarlo();
            const r = this.monteCarloResults;
            return `Based on 10,000 Monte Carlo simulations over 10 years:\n\n` +
                   `• Best case (95th): ${this.fmt(r.p95)}\n` +
                   `• Expected (median): ${this.fmt(r.p50)}\n` +
                   `• Worst case (5th): ${this.fmt(r.p5)}\n\n` +
                   `This assumes 7% average return with 18% volatility and ${this.fmt(this.fireInputs?.savings || 2000)}/month contributions.`;
        }
        
        // Recurring / Cash flow queries
        if (q.includes('recurring') || q.includes('cash flow') || q.includes('monthly')) {
            this.initRecurring();
            const items = this.data.recurring.filter(r => r.active);
            const income = items.filter(r => r.type === 'income').reduce((s, r) => s + r.amount, 0);
            const expense = items.filter(r => r.type === 'expense').reduce((s, r) => s + r.amount, 0);
            return `Your recurring transactions:\n\n` +
                   `• Monthly income: ${this.fmt(income)}\n` +
                   `• Monthly expenses: ${this.fmt(expense)}\n` +
                   `• Net monthly: ${this.fmt(income - expense)}\n` +
                   `• Annual surplus: ${this.fmt((income - expense) * 12)}\n\n` +
                   `You have ${items.length} active recurring items.`;
        }
        
        // Correlation queries
        if (q.includes('correlation') || q.includes('diversif')) {
            return `Your portfolio correlation analysis:\n\n` +
                   `• BTC-ADA: 0.85 (high positive)\n` +
                   `• BTC-TSLA: 0.45 (moderate)\n` +
                   `• BTC-MSTR: 0.92 (very high)\n\n` +
                   `High correlation between crypto assets suggests concentration risk. Consider adding uncorrelated assets for better diversification.`;
        }
        
        // Return null to signal no match - let original handler take over
        return null;
    }
});

// Override processQuery with enhanced version
const originalProcessQuery = App.processQuery;
App.processQuery = function(query) {
    // Try enhanced processing first
    const enhanced = this.enhancedProcessQuery(query);
    // If enhanced returned a valid response, use it
    if (enhanced) {
        return enhanced;
    }
    // Fall back to original processing
    return originalProcessQuery.call(this, query);
};

// Update showTab to include new tabs
const origShowTab = App.showTab;
App.showTab = function(tabId) {
    origShowTab.call(this, tabId);
    
    if (tabId === 'journal') this.renderJournal();
    if (tabId === 'income') this.renderIncomeTracker();
    if (tabId === 'benchmark') this.renderBenchmark();
    if (tabId === 'recurring') this.renderRecurring();
    if (tabId === 'vault') this.renderVault();
    if (tabId === 'analytics') {
        this.renderMonteCarloResults();
        this.renderCorrelationMatrix();
    }
};

// Initialize keyboard shortcuts on load
const origInit = App.init;
App.init = function() {
    origInit.call(this);
    this.initKeyboardShortcuts();
};

// ═══════════════════════════════════════════════════════════════════════════
// FIRE CALCULATOR MODULE
// ═══════════════════════════════════════════════════════════════════════════

Object.assign(App, {
    
    fireType: 'regular',
    fireInputs: { expenses: 40000, savings: 2000, returnRate: 7, age: 35, swr: 4, pensionAge: 67 },
    
    initFire() {
        // Load saved inputs
        if (this.data.fireInputs) {
            this.fireInputs = { ...this.fireInputs, ...this.data.fireInputs };
            document.getElementById('fire-expenses').value = this.fireInputs.expenses;
            document.getElementById('fire-savings').value = this.fireInputs.savings;
            document.getElementById('fire-return').value = this.fireInputs.returnRate;
            document.getElementById('fire-age').value = this.fireInputs.age;
            document.getElementById('fire-swr').value = this.fireInputs.swr;
            document.getElementById('fire-pension-age').value = this.fireInputs.pensionAge;
        }
        if (this.data.fireType) {
            this.fireType = this.data.fireType;
        }
        this.updateFire();
    },
    
    updateFire() {
        // Read inputs
        this.fireInputs = {
            expenses: parseFloat(document.getElementById('fire-expenses')?.value) || 40000,
            savings: parseFloat(document.getElementById('fire-savings')?.value) || 2000,
            returnRate: parseFloat(document.getElementById('fire-return')?.value) || 7,
            age: parseFloat(document.getElementById('fire-age')?.value) || 35,
            swr: parseFloat(document.getElementById('fire-swr')?.value) || 4,
            pensionAge: parseFloat(document.getElementById('fire-pension-age')?.value) || 67
        };
        
        // Save inputs
        this.data.fireInputs = this.fireInputs;
        this.data.fireType = this.fireType;
        this.save();
        
        // Calculate FIRE numbers
        const nw = this.calcNetWorth();
        const { expenses, savings, returnRate, age, swr, pensionAge } = this.fireInputs;
        
        // Different FIRE targets
        const leanMultiplier = 0.6;  // 60% of regular expenses
        const fatMultiplier = 1.5;   // 150% of regular expenses
        
        const regularTarget = expenses / (swr / 100);
        const leanTarget = (expenses * leanMultiplier) / (swr / 100);
        const fatTarget = (expenses * fatMultiplier) / (swr / 100);
        const coastTarget = this.calcCoastFire(regularTarget, age, pensionAge, returnRate);
        
        // Years to reach each
        const monthlyReturn = returnRate / 100 / 12;
        const regularYears = this.calcYearsToTarget(nw, regularTarget, savings, monthlyReturn);
        const leanYears = this.calcYearsToTarget(nw, leanTarget, savings, monthlyReturn);
        const fatYears = this.calcYearsToTarget(nw, fatTarget, savings, monthlyReturn);
        const coastYears = nw >= coastTarget ? 0 : this.calcYearsToTarget(nw, coastTarget, savings, monthlyReturn);
        
        // Get current target based on type
        let currentTarget, currentYears;
        switch(this.fireType) {
            case 'lean': currentTarget = leanTarget; currentYears = leanYears; break;
            case 'fat': currentTarget = fatTarget; currentYears = fatYears; break;
            case 'coast': currentTarget = coastTarget; currentYears = coastYears; break;
            default: currentTarget = regularTarget; currentYears = regularYears;
        }
        
        // Update display
        this.setText('fire-number', this.fmt(currentTarget));
        this.setText('fire-number-sub', `Based on ${this.fmt(expenses)}/year × ${Math.round(100/swr)} (${swr}% rule)`);
        
        const progress = Math.min(100, (nw / currentTarget) * 100);
        this.setText('fire-progress-pct', progress.toFixed(1) + '%');
        this.setWidth('fire-progress-fill', progress + '%');
        this.setText('fire-target-value', this.fmt(currentTarget));
        
        // Update type cards
        this.setText('lean-target', this.fmt(leanTarget));
        this.setText('regular-target', this.fmt(regularTarget));
        this.setText('fat-target', this.fmt(fatTarget));
        this.setText('coast-target', this.fmt(coastTarget));
        
        this.setText('lean-years', leanYears <= 0 ? ' Achieved!' : leanYears.toFixed(1) + ' years');
        this.setText('regular-years', regularYears <= 0 ? ' Achieved!' : regularYears.toFixed(1) + ' years');
        this.setText('fat-years', fatYears <= 0 ? ' Achieved!' : fatYears.toFixed(1) + ' years');
        this.setText('coast-years', coastYears <= 0 ? ' Achieved!' : coastYears.toFixed(1) + ' years');
        
        // Update type card styles
        document.querySelectorAll('.fire-type-card').forEach(c => c.classList.remove('active'));
        document.getElementById('fire-' + this.fireType)?.classList.add('active');
        
        // Update summary
        this.setText('fire-current-nw', this.fmt(nw));
        this.setText('fire-years-to', currentYears <= 0 ? 'Now!' : currentYears.toFixed(1) + ' years');
        this.setText('fire-age-at', currentYears <= 0 ? age : Math.round(age + currentYears));
        this.setText('fire-passive', this.fmt(nw * (swr / 100)));
        
        // Render milestones
        this.renderFireMilestones(nw, currentTarget, currentYears, age);
    },
    
    calcYearsToTarget(current, target, monthlySavings, monthlyReturn) {
        if (current >= target) return 0;
        if (monthlySavings <= 0 && monthlyReturn <= 0) return Infinity;
        
        // Future Value formula with monthly contributions
        // FV = PV*(1+r)^n + PMT*((1+r)^n - 1)/r
        // Solve for n iteratively
        let months = 0;
        let value = current;
        const maxMonths = 1200; // 100 years max
        
        while (value < target && months < maxMonths) {
            value = value * (1 + monthlyReturn) + monthlySavings;
            months++;
        }
        
        return months / 12;
    },
    
    calcCoastFire(targetAtRetirement, currentAge, retirementAge, annualReturn) {
        // How much do you need NOW so it grows to target by retirement?
        const years = retirementAge - currentAge;
        if (years <= 0) return targetAtRetirement;
        return targetAtRetirement / Math.pow(1 + annualReturn / 100, years);
    },
    
    setFireType(type) {
        this.fireType = type;
        this.updateFire();
    },
    
    renderFireMilestones(nw, target, yearsToFire, currentAge) {
        const container = document.getElementById('fire-milestones');
        if (!container) return;
        
        const milestones = [
            { pct: 25, name: '25% to FIRE', icon: '🌱' },
            { pct: 50, name: 'Halfway to FIRE', icon: '⚡' },
            { pct: 75, name: '75% to FIRE', icon: '' },
            { pct: 100, name: 'FIRE Achieved!', icon: '' }
        ];
        
        const currentPct = (nw / target) * 100;
        
        container.innerHTML = milestones.map(m => {
            const reached = currentPct >= m.pct;
            const targetValue = target * (m.pct / 100);
            const yearsAway = reached ? 0 : this.calcYearsToTarget(nw, targetValue, this.fireInputs.savings, this.fireInputs.returnRate / 100 / 12);
            const ageAt = Math.round(currentAge + yearsAway);
            
            return `<div class="fire-milestone">
                <div class="fire-milestone-icon ${reached ? 'reached' : 'future'}">${m.icon}</div>
                <div class="fire-milestone-info">
                    <div class="fire-milestone-name">${m.name}</div>
                    <div class="fire-milestone-detail">${this.fmt(targetValue)}</div>
                </div>
                <div class="fire-milestone-date">${reached ? ' Reached' : 'Age ' + ageAt}</div>
            </div>`;
        }).join('');
    }
});

// ═══════════════════════════════════════════════════════════════════════════
// SMART PRICE ALERTS MODULE
// ═══════════════════════════════════════════════════════════════════════════

Object.assign(App, {
    
    priceAlerts: [],
    alertSettings: { browserNotif: false, soundAlerts: true, frequency: 5 },
    alertCheckInterval: null,
    
    initPriceAlerts() {
        if (this.data.priceAlerts) {
            this.priceAlerts = this.data.priceAlerts;
        }
        if (this.data.alertSettings) {
            this.alertSettings = this.data.alertSettings;
        }
        
        // Start checking alerts
        this.startAlertChecker();
    },
    
    renderAlerts() {
        this.initPriceAlerts();
        this.renderAlertsList();
        this.renderTriggeredAlerts();
        this.updateAlertStats();
        this.renderAlertSettings();
    },
    
    getCurrentPrice(asset) {
        if (asset === 'networth') return this.calcNetWorth();
        
        const crypto = this.data.crypto.find(c => c.symbol.toLowerCase() === asset);
        if (crypto) return crypto.price;
        
        const equity = this.data.equities.find(e => e.symbol.toLowerCase() === asset);
        if (equity) return equity.currentPrice || (equity.value / equity.shares);
        
        return 0;
    },
    
    createAlert() {
        const asset = document.getElementById('alert-asset')?.value;
        const condition = document.getElementById('alert-condition')?.value;
        const target = parseFloat(document.getElementById('alert-target')?.value);
        const note = document.getElementById('alert-note')?.value || '';
        
        if (!asset || !condition || isNaN(target)) {
            this.toast('Please fill in all required fields');
            return;
        }
        
        const currentPrice = this.getCurrentPrice(asset);
        
        const alert = {
            id: Date.now(),
            asset,
            condition,
            target,
            note,
            currentPrice,
            createdAt: new Date().toISOString(),
            status: 'active',
            triggered: false,
            triggeredAt: null
        };
        
        this.priceAlerts.push(alert);
        this.saveAlerts();
        this.renderAlerts();
        
        // Clear form
        document.getElementById('alert-target').value = '';
        document.getElementById('alert-note').value = '';
        
        this.toast('Alert created');
    },
    
    createQuickAlerts() {
        const quickAlerts = [
            { asset: 'ada', condition: 'above', target: 0.50, note: 'ADA 50p target' },
            { asset: 'ada', condition: 'above', target: 1.00, note: 'ADA £1 milestone' },
            { asset: 'btc', condition: 'above', target: 100000, note: 'BTC £100K' },
            { asset: 'networth', condition: 'above', target: 1500000, note: '£1.5M Net Worth' }
        ];
        
        quickAlerts.forEach(a => {
            // Check if similar alert exists
            const exists = this.priceAlerts.some(p => 
                p.asset === a.asset && p.condition === a.condition && p.target === a.target && p.status === 'active'
            );
            
            if (!exists) {
                this.priceAlerts.push({
                    id: Date.now() + Math.random() * 1000,
                    ...a,
                    currentPrice: this.getCurrentPrice(a.asset),
                    createdAt: new Date().toISOString(),
                    status: 'active',
                    triggered: false,
                    triggeredAt: null
                });
            }
        });
        
        this.saveAlerts();
        this.renderAlerts();
        this.toast('Quick alerts created');
    },
    
    renderAlertsList() {
        const container = document.getElementById('alerts-list');
        if (!container) return;
        
        const activeAlerts = this.priceAlerts.filter(a => a.status === 'active' || a.status === 'paused');
        
        if (activeAlerts.length === 0) {
            container.innerHTML = '<p style="color:var(--text-muted);text-align:center;padding:30px">No alerts yet. Create your first alert above!</p>';
            return;
        }
        
        container.innerHTML = activeAlerts.map(alert => {
            const currentPrice = this.getCurrentPrice(alert.asset);
            const progress = this.calcAlertProgress(alert, currentPrice);
            const assetNames = { ada: 'ADA', btc: 'BTC', tsla: 'TSLA', mstr: 'MSTR', networth: 'Net Worth' };
            const conditionText = this.getConditionText(alert);
            const iconClass = alert.condition.includes('above') || alert.condition.includes('up') ? 'price-above' : 'price-below';
            const icon = alert.condition.includes('above') ? '📈' : alert.condition.includes('below') ? '↘' : '📊';
            
            return `<div class="alert-item ${alert.status}">
                <div class="alert-icon ${iconClass}">${icon}</div>
                <div class="alert-content">
                    <div class="alert-title">
                        ${assetNames[alert.asset] || alert.asset}
                        <span class="alert-status ${alert.status}">${alert.status === 'active' ? '● Active' : '⏸ Paused'}</span>
                    </div>
                    <div class="alert-condition">${conditionText}</div>
                    ${alert.note ? `<div class="alert-meta"><span>📝 ${alert.note}</span></div>` : ''}
                    <div class="alert-progress">
                        <div class="alert-progress-bar"><div class="alert-progress-fill" style="width:${progress}%"></div></div>
                        <div class="alert-progress-text">
                            <span>Current: ${alert.asset === 'networth' ? this.fmt(currentPrice) : '£' + currentPrice.toFixed(currentPrice < 1 ? 4 : 2)}</span>
                            <span>${progress.toFixed(0)}% to target</span>
                        </div>
                    </div>
                </div>
                <div class="alert-actions">
                    <button class="btn btn-secondary" onclick="App.toggleAlertPause(${alert.id})">${alert.status === 'active' ? '⏸️' : '▶️'}</button>
                    <button class="btn btn-secondary" onclick="App.deleteAlert(${alert.id})">✕</button>
                </div>
            </div>`;
        }).join('');
    },
    
    getConditionText(alert) {
        const targetFmt = alert.asset === 'networth' ? this.fmt(alert.target) : '£' + alert.target.toFixed(alert.target < 1 ? 4 : 2);
        switch(alert.condition) {
            case 'above': return `Price goes above ${targetFmt}`;
            case 'below': return `Price drops below ${targetFmt}`;
            case 'pct_up': return `Increases by ${alert.target}%`;
            case 'pct_down': return `Decreases by ${alert.target}%`;
            default: return `Target: ${targetFmt}`;
        }
    },
    
    calcAlertProgress(alert, currentPrice) {
        if (alert.condition === 'above') {
            if (currentPrice >= alert.target) return 100;
            const startPrice = alert.currentPrice || currentPrice * 0.5;
            const range = alert.target - startPrice;
            return range > 0 ? Math.max(0, Math.min(100, ((currentPrice - startPrice) / range) * 100)) : 0;
        }
        if (alert.condition === 'below') {
            if (currentPrice <= alert.target) return 100;
            const startPrice = alert.currentPrice || currentPrice * 1.5;
            const range = startPrice - alert.target;
            return range > 0 ? Math.max(0, Math.min(100, ((startPrice - currentPrice) / range) * 100)) : 0;
        }
        return 50;
    },
    
    renderTriggeredAlerts() {
        const triggered = this.priceAlerts.filter(a => a.triggered);
        const section = document.getElementById('triggered-alerts-section');
        const list = document.getElementById('triggered-alerts-list');
        
        if (!section || !list) return;
        
        if (triggered.length === 0) {
            section.style.display = 'none';
            return;
        }
        
        section.style.display = 'block';
        list.innerHTML = triggered.slice(0, 5).map(a => {
            const assetNames = { ada: 'ADA', btc: 'BTC', tsla: 'TSLA', mstr: 'MSTR', networth: 'Net Worth' };
            return `<div style="padding:8px 0;border-bottom:1px solid var(--border-color);display:flex;justify-content:space-between">
                <span><strong>${assetNames[a.asset]}</strong> hit ${a.asset === 'networth' ? this.fmt(a.target) : '£' + a.target}</span>
                <span style="color:var(--text-muted);font-size:12px">${new Date(a.triggeredAt).toLocaleString('en-GB')}</span>
            </div>`;
        }).join('');
    },
    
    updateAlertStats() {
        const active = this.priceAlerts.filter(a => a.status === 'active').length;
        const triggered = this.priceAlerts.filter(a => a.triggered && new Date(a.triggeredAt).toDateString() === new Date().toDateString()).length;
        const total = this.priceAlerts.length;
        
        this.setText('alerts-active', active);
        this.setText('alerts-triggered', triggered);
        this.setText('alerts-total', total);
    },
    
    toggleAlertPause(id) {
        const alert = this.priceAlerts.find(a => a.id === id);
        if (alert) {
            alert.status = alert.status === 'active' ? 'paused' : 'active';
            this.saveAlerts();
            this.renderAlerts();
        }
    },
    
    deleteAlert(id) {
        this.priceAlerts = this.priceAlerts.filter(a => a.id !== id);
        this.saveAlerts();
        this.renderAlerts();
        this.toast('Alert deleted');
    },
    
    pauseAllAlerts() {
        this.priceAlerts.forEach(a => { if (a.status === 'active') a.status = 'paused'; });
        this.saveAlerts();
        this.renderAlerts();
        this.toast('All alerts paused');
    },
    
    clearTriggeredAlerts() {
        this.priceAlerts = this.priceAlerts.filter(a => !a.triggered);
        this.saveAlerts();
        this.renderAlerts();
        this.toast('Triggered alerts cleared');
    },
    
    checkAlerts() {
        let anyTriggered = false;
        
        this.priceAlerts.forEach(alert => {
            if (alert.status !== 'active' || alert.triggered) return;
            
            const currentPrice = this.getCurrentPrice(alert.asset);
            let triggered = false;
            
            switch(alert.condition) {
                case 'above': triggered = currentPrice >= alert.target; break;
                case 'below': triggered = currentPrice <= alert.target; break;
                case 'pct_up': triggered = currentPrice >= alert.currentPrice * (1 + alert.target / 100); break;
                case 'pct_down': triggered = currentPrice <= alert.currentPrice * (1 - alert.target / 100); break;
            }
            
            if (triggered) {
                alert.triggered = true;
                alert.triggeredAt = new Date().toISOString();
                alert.status = 'triggered';
                anyTriggered = true;
                
                this.fireAlertNotification(alert);
            }
        });
        
        if (anyTriggered) {
            this.saveAlerts();
            if (document.getElementById('tab-alerts')?.classList.contains('hidden') === false) {
                this.renderAlerts();
            }
        }
    },
    
    fireAlertNotification(alert) {
        const assetNames = { ada: 'ADA', btc: 'BTC', tsla: 'TSLA', mstr: 'MSTR', networth: 'Net Worth' };
        const message = `${assetNames[alert.asset]} hit ${alert.asset === 'networth' ? this.fmt(alert.target) : '£' + alert.target}!`;
        
        // Toast
        this.toast('' + message, 'success');
        
        // Browser notification
        if (this.alertSettings.browserNotif && 'Notification' in window && Notification.permission === 'granted') {
            new Notification('FCC Price Alert', { body: message, icon: '🔔' });
        }
        
        // Sound
        if (this.alertSettings.soundAlerts) {
            this.playAlertSound();
        }
    },
    
    playAlertSound() {
        try {
            const ctx = new (window.AudioContext || window.webkitAudioContext)();
            const osc = ctx.createOscillator();
            const gain = ctx.createGain();
            osc.connect(gain);
            gain.connect(ctx.destination);
            osc.frequency.value = 800;
            gain.gain.value = 0.1;
            osc.start();
            osc.stop(ctx.currentTime + 0.2);
        } catch(e) {
            // Audio not supported or blocked - silent fail is appropriate
        }
    },
    
    startAlertChecker() {
        if (this.alertCheckInterval) clearInterval(this.alertCheckInterval);
        const freq = (this.alertSettings.frequency || 5) * 60 * 1000;
        this.alertCheckInterval = setInterval(() => this.checkAlerts(), freq);
    },
    
    saveAlerts() {
        this.data.priceAlerts = this.priceAlerts;
        this.data.alertSettings = this.alertSettings;
        this.save();
    },
    
    togglePriceAlertSetting(setting) {
        this.alertSettings[setting] = !this.alertSettings[setting];
        
        if (setting === 'browserNotif' && this.alertSettings.browserNotif) {
            if ('Notification' in window && Notification.permission === 'default') {
                Notification.requestPermission();
            }
        }
        
        const toggle = document.getElementById('toggle-' + setting.replace(/([A-Z])/g, '-$1').toLowerCase());
        if (toggle) toggle.classList.toggle('active', this.alertSettings[setting]);
        
        this.saveAlerts();
    },
    
    setAlertFrequency() {
        this.alertSettings.frequency = parseInt(document.getElementById('alert-frequency')?.value) || 5;
        this.saveAlerts();
        this.startAlertChecker();
    },
    
    renderAlertSettings() {
        const s = this.alertSettings;
        document.getElementById('toggle-browser-notif')?.classList.toggle('active', s.browserNotif);
        document.getElementById('toggle-sound-alerts')?.classList.toggle('active', s.soundAlerts !== false);
        const freq = document.getElementById('alert-frequency');
        if (freq) freq.value = s.frequency || 5;
    }
});

// ═══════════════════════════════════════════════════════════════════════════
// WHAT-IF SCENARIO SIMULATOR MODULE
// ═══════════════════════════════════════════════════════════════════════════

Object.assign(App, {
    
    simBasePrices: {},
    simCurrentPrices: {},
    simMode: 'price',
    savedScenarios: [],
    
    initSimulator() {
        // Capture current prices as baseline
        this.simBasePrices = {};
        this.simCurrentPrices = {};
        
        // Get crypto prices
        this.data.crypto.forEach(c => {
            this.simBasePrices[c.symbol.toLowerCase()] = c.price;
            this.simCurrentPrices[c.symbol.toLowerCase()] = c.price;
        });
        
        // Get equity prices
        this.data.equities.forEach(e => {
            const sym = e.symbol.toLowerCase();
            this.simBasePrices[sym] = e.currentPrice || (e.value / e.shares);
            this.simCurrentPrices[sym] = this.simBasePrices[sym];
        });
        
        // Load saved scenarios
        if (this.data.savedScenarios) {
            this.savedScenarios = this.data.savedScenarios;
        }
        
        this.updateSimulatorDisplay();
        this.renderSavedScenarios();
    },
    
    updateSimulator() {
        // Read slider values and update projected prices
        const sliders = ['ada', 'btc', 'tsla', 'mstr'];
        
        sliders.forEach(sym => {
            const slider = document.getElementById('sim-' + sym);
            if (!slider || !this.simBasePrices[sym]) return;
            
            const pct = parseFloat(slider.value);
            const basePrice = this.simBasePrices[sym];
            const newPrice = basePrice * (pct / 100);
            this.simCurrentPrices[sym] = newPrice;
            
            // Update display
            const projectedEl = document.getElementById(sym + '-projected');
            const changeEl = document.getElementById(sym + '-change');
            
            if (projectedEl) {
                projectedEl.textContent = this.formatPrice(newPrice);
            }
            if (changeEl) {
                const change = pct - 100;
                changeEl.textContent = (change >= 0 ? '+' : '') + change.toFixed(0) + '%';
                changeEl.className = 'slider-change ' + (change >= 0 ? 'positive' : 'negative');
            }
        });
        
        this.updateSimulatorDisplay();
    },
    
    formatPrice(price) {
        if (price >= 1000) return '£' + price.toLocaleString('en-GB', { maximumFractionDigits: 0 });
        if (price >= 1) return '£' + price.toFixed(2);
        return '£' + price.toFixed(4);
    },
    
    updateSimulatorDisplay() {
        // Calculate current values
        const currentCrypto = this.calcCrypto().value;
        const currentEquity = this.calcEquity().value;
        const currentDebt = this.calcLiabilities().total;
        const currentNW = currentCrypto + currentEquity - currentDebt;
        
        // Calculate projected values with new prices
        let projectedCrypto = 0;
        this.data.crypto.forEach(c => {
            const sym = c.symbol.toLowerCase();
            const price = this.simCurrentPrices[sym] !== undefined ? this.simCurrentPrices[sym] : c.price;
            projectedCrypto += c.qty * price;
        });
        
        let projectedEquity = 0;
        this.data.equities.forEach(e => {
            const sym = e.symbol.toLowerCase();
            const price = this.simCurrentPrices[sym] !== undefined ? this.simCurrentPrices[sym] : (e.currentPrice || e.value / e.shares);
            projectedEquity += e.shares * price;
        });
        
        const projectedDebt = currentDebt; // Debt doesn't change with prices
        const projectedNW = projectedCrypto + projectedEquity - projectedDebt;
        
        // Update current panel
        this.setText('sim-current-nw', this.fmt(currentNW));
        this.setText('sim-current-crypto', this.fmt(currentCrypto));
        this.setText('sim-current-equity', this.fmt(currentEquity));
        this.setText('sim-current-debt', '-' + this.fmt(currentDebt));
        
        // Update projected panel
        this.setText('sim-projected-nw', this.fmt(projectedNW));
        this.setText('sim-projected-crypto', this.fmt(projectedCrypto));
        this.setText('sim-projected-equity', this.fmt(projectedEquity));
        this.setText('sim-projected-debt', '-' + this.fmt(projectedDebt));
        
        // Update delta
        const delta = projectedNW - currentNW;
        const deltaPct = currentNW > 0 ? (delta / currentNW) * 100 : 0;
        
        const deltaEl = document.getElementById('sim-delta');
        const deltaPctEl = document.getElementById('sim-delta-pct');
        const projectedNWEl = document.getElementById('sim-projected-nw');
        
        if (deltaEl) {
            deltaEl.textContent = (delta >= 0 ? '+' : '') + this.fmt(delta);
            deltaEl.className = 'delta-value ' + (delta >= 0 ? 'positive' : 'negative');
        }
        if (deltaPctEl) {
            deltaPctEl.textContent = (deltaPct >= 0 ? '+' : '') + deltaPct.toFixed(1) + '%';
            deltaPctEl.className = 'delta-value ' + (deltaPct >= 0 ? 'positive' : 'negative');
        }
        if (projectedNWEl) {
            projectedNWEl.className = 'panel-value ' + (delta >= 0 ? 'positive' : 'negative');
        }
        
        // Update tax impact
        this.updateTaxImpact(projectedCrypto - currentCrypto, projectedEquity - currentEquity);
        
        // Update slider current values display
        this.updateSliderDisplays();
    },
    
    updateSliderDisplays() {
        ['ada', 'btc', 'tsla', 'mstr'].forEach(sym => {
            const currentEl = document.getElementById(sym + '-current');
            if (currentEl && this.simBasePrices[sym]) {
                currentEl.textContent = this.formatPrice(this.simBasePrices[sym]);
            }
        });
    },
    
    updateTaxImpact(cryptoGain, equityGain) {
        // Simplified tax calculation
        const totalGain = Math.max(0, cryptoGain + equityGain);
        const allowance = 3000;
        const taxable = Math.max(0, totalGain - allowance);
        const taxDue = taxable * 0.20; // Assume higher rate
        
        this.setText('sim-tax-gain', this.fmt(totalGain));
        this.setText('sim-tax-allowance', this.fmt(allowance));
        this.setText('sim-tax-taxable', this.fmt(taxable));
        this.setText('sim-tax-due', this.fmt(taxDue));
    },
    
    resetSimulator() {
        ['ada', 'btc', 'tsla', 'mstr'].forEach(sym => {
            const slider = document.getElementById('sim-' + sym);
            if (slider) slider.value = 100;
        });
        
        // Reset prices to base
        Object.keys(this.simBasePrices).forEach(sym => {
            this.simCurrentPrices[sym] = this.simBasePrices[sym];
        });
        
        this.updateSimulator();
        this.toast('Simulator reset');
    },
    
    setScenarioMode(mode, btn) {
        this.simMode = mode;
        
        document.querySelectorAll('.scenario-tab').forEach(t => t.classList.remove('active'));
        if (btn) btn.classList.add('active');
        
        document.getElementById('sim-price-controls').style.display = mode === 'price' ? 'grid' : 'none';
        document.getElementById('sim-holdings-controls').style.display = mode === 'holdings' ? 'grid' : 'none';
        document.getElementById('sim-debt-controls').style.display = mode === 'debt' ? 'grid' : 'none';
        
        if (mode === 'holdings') this.renderHoldingsControls();
        if (mode === 'debt') this.renderDebtControls();
    },
    
    renderHoldingsControls() {
        const container = document.getElementById('sim-holdings-controls');
        if (!container) return;
        
        container.innerHTML = `
            <div class="slider-item">
                <div style="text-align:center;padding:20px;color:var(--text-muted)">
                    <p>🚧 Holdings simulation coming soon</p>
                    <p style="font-size:12px;margin-top:8px">Simulate buying/selling specific quantities</p>
                </div>
            </div>
        `;
    },
    
    renderDebtControls() {
        const container = document.getElementById('sim-debt-controls');
        if (!container) return;
        
        container.innerHTML = `
            <div class="slider-item">
                <div style="text-align:center;padding:20px;color:var(--text-muted)">
                    <p>🚧 Debt payoff simulation coming soon</p>
                    <p style="font-size:12px;margin-top:8px">See impact of extra payments</p>
                </div>
            </div>
        `;
    },
    
    applyQuickScenario(scenario) {
        // Reset first
        ['ada', 'btc', 'tsla', 'mstr'].forEach(sym => {
            const slider = document.getElementById('sim-' + sym);
            if (slider) slider.value = 100;
        });
        
        switch(scenario) {
            case 'bull':
                ['ada', 'btc', 'tsla', 'mstr'].forEach(sym => {
                    const slider = document.getElementById('sim-' + sym);
                    if (slider) slider.value = 150;
                });
                break;
            case 'bear':
                ['ada', 'btc', 'tsla', 'mstr'].forEach(sym => {
                    const slider = document.getElementById('sim-' + sym);
                    if (slider) slider.value = 50;
                });
                break;
            case 'ada1':
                // ADA to £1 from current price
                const adaSlider = document.getElementById('sim-ada');
                if (adaSlider && this.simBasePrices.ada) {
                    const targetPct = (1 / this.simBasePrices.ada) * 100;
                    adaSlider.value = Math.min(500, targetPct);
                }
                break;
            case 'btc150k':
                const btcSlider = document.getElementById('sim-btc');
                if (btcSlider && this.simBasePrices.btc) {
                    const targetPct = (150000 / this.simBasePrices.btc) * 100;
                    btcSlider.value = Math.min(300, targetPct);
                }
                break;
            case 'crash':
                ['ada', 'btc'].forEach(sym => {
                    const slider = document.getElementById('sim-' + sym);
                    if (slider) slider.value = 20;
                });
                break;
            case 'debtfree':
                // This would be handled differently in debt mode
                this.toast('Switch to Debt Payoff mode for this scenario');
                return;
        }
        
        this.updateSimulator();
        this.toast('Scenario applied: ' + scenario);
    },
    
    saveScenario() {
        const name = prompt('Name this scenario:', 'Scenario ' + (this.savedScenarios.length + 1));
        if (!name) return;
        
        const scenario = {
            id: Date.now(),
            name,
            date: new Date().toISOString(),
            prices: { ...this.simCurrentPrices },
            sliders: {}
        };
        
        ['ada', 'btc', 'tsla', 'mstr'].forEach(sym => {
            const slider = document.getElementById('sim-' + sym);
            if (slider) scenario.sliders[sym] = parseFloat(slider.value);
        });
        
        this.savedScenarios.push(scenario);
        this.data.savedScenarios = this.savedScenarios;
        this.save();
        
        this.renderSavedScenarios();
        this.toast('Scenario saved');
    },
    
    renderSavedScenarios() {
        const container = document.getElementById('saved-scenarios-list');
        const countEl = document.getElementById('saved-scenarios-count');
        
        if (countEl) countEl.textContent = this.savedScenarios.length;
        
        if (!container) return;
        
        if (this.savedScenarios.length === 0) {
            container.innerHTML = '<p style="color:var(--text-muted);text-align:center;padding:20px">No saved scenarios yet. Adjust sliders and click "Save Scenario".</p>';
            return;
        }
        
        container.innerHTML = this.savedScenarios.map(s => `
            <div class="saved-scenario-item">
                <div class="saved-scenario-info">
                    <div class="saved-scenario-name">${s.name}</div>
                    <div class="saved-scenario-detail">Saved ${new Date(s.date).toLocaleDateString('en-GB')}</div>
                </div>
                <div class="saved-scenario-actions">
                    <button class="btn btn-primary" style="padding:6px 12px;font-size:11px" onclick="App.loadScenario(${s.id})">Load</button>
                    <button class="btn btn-secondary" style="padding:6px 12px;font-size:11px" onclick="App.deleteScenario(${s.id})">✕</button>
                </div>
            </div>
        `).join('');
    },
    
    loadScenario(id) {
        const scenario = this.savedScenarios.find(s => s.id === id);
        if (!scenario) return;
        
        Object.keys(scenario.sliders).forEach(sym => {
            const slider = document.getElementById('sim-' + sym);
            if (slider) slider.value = scenario.sliders[sym];
        });
        
        this.updateSimulator();
        this.toast('Loaded: ' + scenario.name);
    },
    
    deleteScenario(id) {
        this.savedScenarios = this.savedScenarios.filter(s => s.id !== id);
        this.data.savedScenarios = this.savedScenarios;
        this.save();
        this.renderSavedScenarios();
        this.toast('Scenario deleted');
    }
});

// ═══════════════════════════════════════════════════════════════════════════
// API INTEGRATIONS MODULE
// ═══════════════════════════════════════════════════════════════════════════

Object.assign(App, {
    
    integrations: {
        coinbase: { name: 'Coinbase', type: 'exchange', connected: false, lastSync: null },
        binance: { name: 'Binance', type: 'exchange', connected: false, lastSync: null },
        kraken: { name: 'Kraken', type: 'exchange', connected: false, lastSync: null },
        yahoo: { name: 'Yahoo Finance', type: 'market', connected: true, lastSync: new Date().toISOString() },
        plaid: { name: 'Open Banking', type: 'bank', connected: false, lastSync: null }
    },
    
    syncLog: [],
    
    initIntegrations() {
        if (this.data.integrations) {
            Object.assign(this.integrations, this.data.integrations);
        }
        if (this.data.integrationSettings?.autoSync) {
            this.runAutoSync();
        }
    },
    
    renderIntegrations() {
        this.updateIntegrationStatuses();
        this.renderSyncLog();
    },
    
    updateIntegrationStatuses() {
        Object.keys(this.integrations).forEach(id => {
            const int = this.integrations[id];
            const dot = document.getElementById('status-' + id);
            const text = document.getElementById('status-text-' + id);
            const time = document.getElementById('status-time-' + id);
            const card = document.getElementById('int-' + id);
            
            if (dot) {
                dot.className = 'status-dot ' + (int.connected ? 'connected' : 'disconnected');
            }
            if (text) {
                text.textContent = int.connected ? 'Connected' : (id === 'plaid' ? 'Coming Soon' : 'Not connected');
            }
            if (time && int.lastSync) {
                const ago = this.timeAgo(new Date(int.lastSync));
                time.textContent = ago;
            }
            if (card) {
                card.classList.toggle('connected', int.connected);
            }
        });
    },
    
    timeAgo(date) {
        const seconds = Math.floor((new Date() - date) / 1000);
        if (seconds < 60) return 'Just now';
        if (seconds < 3600) return Math.floor(seconds / 60) + 'm ago';
        if (seconds < 86400) return Math.floor(seconds / 3600) + 'h ago';
        return Math.floor(seconds / 86400) + 'd ago';
    },
    
    connectIntegration(id) {
        const apiKey = document.getElementById('api-' + id)?.value;
        const secret = document.getElementById('secret-' + id)?.value;
        
        if (!apiKey || !secret) {
            this.toast('Please enter API key and secret');
            return;
        }
        
        this.addSyncLog('info', `Connecting to ${this.integrations[id].name}...`);
        
        // Simulate connection (in production, this would make real API calls)
        setTimeout(() => {
            this.integrations[id].connected = true;
            this.integrations[id].lastSync = new Date().toISOString();
            
            // Store if enabled
            if (this.data.integrationSettings?.storeKeys) {
                if (!this.data.apiKeys) this.data.apiKeys = {};
                this.data.apiKeys[id] = { key: btoa(apiKey), secret: btoa(secret) };
            }
            
            this.data.integrations = this.integrations;
            this.save();
            
            this.addSyncLog('success', `Connected to ${this.integrations[id].name} successfully`);
            this.updateIntegrationStatuses();
            this.toast('Connected to ' + this.integrations[id].name);
            
            // Clear inputs
            document.getElementById('api-' + id).value = '';
            document.getElementById('secret-' + id).value = '';
        }, 1500);
    },
    
    syncIntegration(id) {
        const int = this.integrations[id];
        
        if (id === 'yahoo') {
            this.syncYahooFinance();
            return;
        }
        
        if (!int.connected) {
            this.toast('Please connect first');
            return;
        }
        
        this.addSyncLog('info', `Syncing ${int.name}...`);
        
        // Simulate sync
        setTimeout(() => {
            int.lastSync = new Date().toISOString();
            this.data.integrations = this.integrations;
            this.save();
            
            // Simulate importing some data
            const mockData = this.generateMockSyncData(id);
            this.addSyncLog('success', `Synced ${int.name}: ${mockData.count} assets updated`);
            this.updateIntegrationStatuses();
            this.toast('Sync complete');
        }, 2000);
    },
    
    syncYahooFinance() {
        this.addSyncLog('info', 'Fetching latest stock prices...');
        
        // Use existing refresh functionality
        if (this.fetchLivePrices) {
            this.fetchLivePrices().then(() => {
                this.integrations.yahoo.lastSync = new Date().toISOString();
                this.addSyncLog('success', 'Stock prices updated from Yahoo Finance');
                this.updateIntegrationStatuses();
            }).catch(err => {
                this.addSyncLog('error', 'Failed to fetch prices: ' + err.message);
            });
        } else {
            setTimeout(() => {
                this.integrations.yahoo.lastSync = new Date().toISOString();
                this.addSyncLog('success', 'Stock prices refreshed');
                this.updateIntegrationStatuses();
            }, 1000);
        }
    },
    
    generateMockSyncData(id) {
        // Simulate data import
        return { count: Math.floor(Math.random() * 5) + 1 };
    },
    
    disconnectIntegration(id) {
        this.integrations[id].connected = false;
        this.integrations[id].lastSync = null;
        
        if (this.data.apiKeys) {
            delete this.data.apiKeys[id];
        }
        
        this.data.integrations = this.integrations;
        this.save();
        
        this.addSyncLog('info', `Disconnected from ${this.integrations[id].name}`);
        this.updateIntegrationStatuses();
        this.toast('Disconnected');
    },
    
    addSyncLog(type, message) {
        const now = new Date();
        const time = now.toTimeString().split(' ')[0];
        
        this.syncLog.unshift({ time, type, message });
        if (this.syncLog.length > 50) this.syncLog.pop();
        
        this.renderSyncLog();
    },
    
    renderSyncLog() {
        const log = document.getElementById('sync-log');
        if (!log) return;
        
        if (this.syncLog.length === 0) {
            log.innerHTML = '<div class="sync-log-entry"><span class="sync-log-time">--:--:--</span><span class="sync-log-msg info">Waiting for sync activity...</span></div>';
            return;
        }
        
        log.innerHTML = this.syncLog.map(entry => 
            `<div class="sync-log-entry"><span class="sync-log-time">${entry.time}</span><span class="sync-log-msg ${entry.type}">${entry.message}</span></div>`
        ).join('');
    },
    
    clearSyncLog() {
        this.syncLog = [];
        this.renderSyncLog();
        this.toast('Log cleared');
    },
    
    runAutoSync() {
        const connected = Object.keys(this.integrations).filter(id => this.integrations[id].connected);
        connected.forEach(id => this.syncIntegration(id));
    },
    
    toggleIntegrationSetting(setting) {
        if (!this.data.integrationSettings) this.data.integrationSettings = {};
        this.data.integrationSettings[setting] = !this.data.integrationSettings[setting];
        
        const toggle = document.getElementById('toggle-' + setting.replace(/([A-Z])/g, '-$1').toLowerCase());
        if (toggle) toggle.classList.toggle('active', this.data.integrationSettings[setting]);
        
        this.save();
    },
    
    setSyncInterval() {
        const interval = parseInt(document.getElementById('sync-interval')?.value) || 15;
        if (!this.data.integrationSettings) this.data.integrationSettings = {};
        this.data.integrationSettings.syncInterval = interval;
        this.save();
    }
});

// ═══════════════════════════════════════════════════════════════════════════
// FAMILY DASHBOARD MODULE
// ═══════════════════════════════════════════════════════════════════════════

Object.assign(App, {
    
    defaultFamilyMembers: [
        { id: 'primary', name: 'David', role: 'Primary', type: 'primary', isActive: true }
    ],
    
    initFamily() {
        if (!this.data.familyMembers) {
            this.data.familyMembers = [...this.defaultFamilyMembers];
        }
        if (!this.data.familySettings) {
            this.data.familySettings = { combined: true, shareDebt: true, familyPrivacy: false };
        }
    },
    
    renderFamily() {
        this.initFamily();
        this.renderFamilyMembers();
        this.renderFamilyCombined();
        this.renderFamilyPie();
        this.renderFamilySettings();
    },
    
    renderFamilyMembers() {
        const grid = document.getElementById('family-members-grid');
        if (!grid) return;
        
        const members = this.data.familyMembers || this.defaultFamilyMembers;
        
        let html = members.map(m => {
            const nw = m.id === 'primary' ? this.calcNetWorth() : (m.networth || 0);
            const assets = m.id === 'primary' ? this.calcTotalAssets() : (m.assets || 0);
            const debt = m.id === 'primary' ? this.calcLiabilities().total : (m.debt || 0);
            
            return `<div class="family-member-card ${m.isActive ? 'active' : ''}" onclick="App.selectFamilyMember('${m.id}')">
                <div class="family-member-header">
                    <div class="family-avatar ${m.type}">${this.getAvatarEmoji(m.type)}</div>
                    <div>
                        <div class="family-member-name">${m.name}</div>
                        <div class="family-member-role">${m.role}</div>
                    </div>
                    <div class="visibility-toggle" style="margin-left:auto">
                        <span class="visibility-icon">${m.isActive ? '👁️' : '👁️‍🗨️'}</span>
                    </div>
                </div>
                <div class="family-member-stats">
                    <div class="family-stat">
                        <div class="family-stat-label">Net Worth</div>
                        <div class="family-stat-value privacy-target" style="color:var(--accent-green)">${this.fmt(nw)}</div>
                    </div>
                    <div class="family-stat">
                        <div class="family-stat-label">Assets</div>
                        <div class="family-stat-value privacy-target">${this.fmt(assets)}</div>
                    </div>
                    <div class="family-stat">
                        <div class="family-stat-label">Debt</div>
                        <div class="family-stat-value privacy-target" style="color:var(--accent-red)">${this.fmt(debt)}</div>
                    </div>
                    <div class="family-stat">
                        <div class="family-stat-label">% of Total</div>
                        <div class="family-stat-value">${this.calcFamilyContribution(m)}%</div>
                    </div>
                </div>
            </div>`;
        }).join('');
        
        // Add member button
        html += `<div class="add-member-card" onclick="App.showAddMemberModal()">
            <div class="add-member-icon">+</div>
            <div class="add-member-text">Add Family Member</div>
        </div>`;
        
        grid.innerHTML = html;
        this.setText('member-count', members.length);
    },
    
    getAvatarEmoji(type) {
        return { primary: '👨', partner: '👩', child: '👧', other: '👤' }[type] || '👤';
    },
    
    calcFamilyContribution(member) {
        const total = this.calcFamilyTotalNW();
        if (total <= 0) return 0;
        const memberNW = member.id === 'primary' ? this.calcNetWorth() : (member.networth || 0);
        return ((memberNW / total) * 100).toFixed(1);
    },
    
    calcFamilyTotalNW() {
        const members = this.data.familyMembers || [];
        let total = 0;
        members.forEach(m => {
            if (m.id === 'primary') {
                total += this.calcNetWorth();
            } else {
                total += m.networth || 0;
            }
        });
        return total;
    },
    
    calcFamilyTotalAssets() {
        const members = this.data.familyMembers || [];
        let total = 0;
        members.forEach(m => {
            if (m.id === 'primary') {
                total += this.calcTotalAssets();
            } else {
                total += m.assets || 0;
            }
        });
        return total;
    },
    
    calcFamilyTotalDebt() {
        const members = this.data.familyMembers || [];
        let total = 0;
        members.forEach(m => {
            if (m.id === 'primary') {
                total += this.calcLiabilities().total;
            } else {
                total += m.debt || 0;
            }
        });
        return total;
    },
    
    renderFamilyCombined() {
        this.setText('family-total-nw', this.fmt(this.calcFamilyTotalNW()));
        this.setText('family-total-assets', this.fmt(this.calcFamilyTotalAssets()));
        this.setText('family-total-debt', this.fmt(this.calcFamilyTotalDebt()));
        this.setText('family-monthly', this.fmt(this.calcLiabilities().monthly));
    },
    
    renderFamilyPie() {
        const svg = document.getElementById('family-pie');
        const breakdown = document.getElementById('family-breakdown');
        if (!svg || !breakdown) return;
        
        const members = this.data.familyMembers || [];
        const total = this.calcFamilyTotalNW();
        const colors = ['#00ff88', '#8844dd', '#4488ff', '#ffaa00', '#ff4466'];
        
        let angle = 0;
        let paths = '';
        let legendHtml = '';
        
        members.forEach((m, i) => {
            const nw = m.id === 'primary' ? this.calcNetWorth() : (m.networth || 0);
            const pct = total > 0 ? (nw / total) * 100 : 0;
            if (pct <= 0) return;
            
            const startAngle = angle;
            const endAngle = angle + (pct / 100) * 360;
            const color = colors[i % colors.length];
            
            const x1 = 50 + 40 * Math.cos((startAngle - 90) * Math.PI / 180);
            const y1 = 50 + 40 * Math.sin((startAngle - 90) * Math.PI / 180);
            const x2 = 50 + 40 * Math.cos((endAngle - 90) * Math.PI / 180);
            const y2 = 50 + 40 * Math.sin((endAngle - 90) * Math.PI / 180);
            
            const largeArc = pct > 50 ? 1 : 0;
            
            if (pct >= 99.9) {
                paths += `<circle cx="50" cy="50" r="40" fill="${color}"/>`;
            } else {
                paths += `<path d="M50,50 L${x1},${y1} A40,40 0 ${largeArc},1 ${x2},${y2} Z" fill="${color}"/>`;
            }
            
            legendHtml += `<div style="display:flex;align-items:center;gap:10px;margin-bottom:12px">
                <div style="width:16px;height:16px;border-radius:4px;background:${color}"></div>
                <div style="flex:1"><strong>${m.name}</strong><br><span style="color:var(--text-muted);font-size:12px">${m.role}</span></div>
                <div style="text-align:right"><strong>${this.fmt(nw)}</strong><br><span style="color:var(--text-muted);font-size:12px">${pct.toFixed(1)}%</span></div>
            </div>`;
            
            angle = endAngle;
        });
        
        paths += `<circle cx="50" cy="50" r="25" fill="var(--bg-card)"/>`;
        svg.innerHTML = paths;
        breakdown.innerHTML = legendHtml || '<p style="color:var(--text-muted)">Add family members to see breakdown</p>';
    },
    
    showAddMemberModal() {
        const body = `
            <div class="form-group"><label class="form-label">Name</label><input type="text" class="form-input" id="member-name" placeholder="e.g., Sarah"></div>
            <div class="form-group"><label class="form-label">Role</label>
                <select class="form-input" id="member-role">
                    <option value="partner">Partner / Spouse</option>
                    <option value="child">Child</option>
                    <option value="other">Other</option>
                </select>
            </div>
            <div class="form-group"><label class="form-label">Net Worth</label><input type="number" class="form-input" id="member-nw" placeholder="0"></div>
            <div class="form-group"><label class="form-label">Total Assets</label><input type="number" class="form-input" id="member-assets" placeholder="0"></div>
            <div class="form-group"><label class="form-label">Total Debt</label><input type="number" class="form-input" id="member-debt" placeholder="0"></div>
            <button class="btn btn-primary" onclick="App.addFamilyMember()" style="width:100%;margin-top:16px">Add Member</button>
        `;
        this.openModal('Add Family Member', body);
    },
    
    addFamilyMember() {
        const name = document.getElementById('member-name')?.value?.trim();
        const role = document.getElementById('member-role')?.value || 'other';
        const nw = parseFloat(document.getElementById('member-nw')?.value) || 0;
        const assets = parseFloat(document.getElementById('member-assets')?.value) || 0;
        const debt = parseFloat(document.getElementById('member-debt')?.value) || 0;
        
        if (!name) { this.toast('Please enter a name'); return; }
        
        if (!this.data.familyMembers) this.data.familyMembers = [...this.defaultFamilyMembers];
        
        this.data.familyMembers.push({
            id: 'member_' + Date.now(),
            name,
            role: role === 'partner' ? 'Partner' : role === 'child' ? 'Child' : 'Family Member',
            type: role,
            isActive: true,
            networth: nw,
            assets,
            debt
        });
        
        this.save();
        this.closeModal();
        this.renderFamily();
        this.toast('Family member added');
    },
    
    selectFamilyMember(id) {
        const members = this.data.familyMembers || [];
        members.forEach(m => { m.isActive = (m.id === id); });
        this.save();
        this.renderFamilyMembers();
    },
    
    toggleFamilySetting(setting) {
        if (!this.data.familySettings) this.data.familySettings = {};
        this.data.familySettings[setting] = !this.data.familySettings[setting];
        const toggle = document.getElementById('toggle-' + setting.replace(/([A-Z])/g, '-$1').toLowerCase());
        if (toggle) toggle.classList.toggle('active', this.data.familySettings[setting]);
        this.save();
    },
    
    renderFamilySettings() {
        const settings = this.data.familySettings || {};
        ['combined', 'shareDebt', 'familyPrivacy'].forEach(s => {
            const id = 'toggle-' + s.replace(/([A-Z])/g, '-$1').toLowerCase();
            const toggle = document.getElementById(id);
            if (toggle) toggle.classList.toggle('active', settings[s] !== false);
        });
    }
});

