// ═══════════════════════════════════════════════════════════════════════════
// MOBILE/TABLET POLISH v7.50 - FAB MENU, SKELETON, ENHANCED TOUCH
// ═══════════════════════════════════════════════════════════════════════════

Object.assign(App, {
    
    fabOpen: false,
    
    // FAB Menu Actions
    fabActions: [
        { icon: '💰', label: 'Add Crypto', action: () => App.openModal('crypto') },
        { icon: '📈', label: 'Add Stock', action: () => App.openModal('equity') },
        { icon: '💳', label: 'Add Spending', action: () => App.openModal('spending') },
        { icon: '📸', label: 'Snapshot', action: () => App.takeSnapshot() },
        { icon: '🔄', label: 'Refresh', action: () => App.refreshAll() }
    ],
    
    // Initialize FAB Menu
    initFabMenu() {
        if (window.innerWidth > 768) return;
        
        let fabMenu = document.getElementById('fab-menu');
        if (fabMenu) return; // Already exists
        
        fabMenu = document.createElement('div');
        fabMenu.id = 'fab-menu';
        fabMenu.className = 'fab-menu';
        
        fabMenu.innerHTML = `
            <div class="fab-options">
                ${this.fabActions.map((a, i) => `
                    <div class="fab-option" style="transition-delay: ${i * 0.05}s">
                        <button class="fab-option-btn" data-fab-action="${i}">${a.icon}</button>
                        <span class="fab-option-label">${a.label}</span>
                    </div>
                `).join('')}
            </div>
            <button class="fab-main" onclick="App.toggleFab()">+</button>
        `;
        
        document.body.appendChild(fabMenu);
        
        // Bind action buttons
        fabMenu.querySelectorAll('.fab-option-btn').forEach(btn => {
            btn.addEventListener('click', (e) => {
                const idx = parseInt(btn.dataset.fabAction);
                this.fabActions[idx]?.action();
                this.toggleFab();
            });
        });
        
        // Close on backdrop click
        document.addEventListener('click', (e) => {
            if (this.fabOpen && !e.target.closest('.fab-menu')) {
                this.toggleFab();
            }
        });
    },
    
    toggleFab() {
        const fabMenu = document.getElementById('fab-menu');
        const fabMain = fabMenu?.querySelector('.fab-main');
        
        this.fabOpen = !this.fabOpen;
        
        if (fabMenu) fabMenu.classList.toggle('open', this.fabOpen);
        if (fabMain) fabMain.classList.toggle('open', this.fabOpen);
        
        // Haptic feedback
        if (navigator.vibrate) navigator.vibrate(10);
    },
    
    // Show skeleton loading state
    showSkeleton(containerId, type = 'card', count = 3) {
        const container = document.getElementById(containerId);
        if (!container) return;
        
        let skeletonHTML = '';
        
        for (let i = 0; i < count; i++) {
            switch(type) {
                case 'card':
                    skeletonHTML += `
                        <div class="skeleton-card skeleton"></div>
                    `;
                    break;
                case 'row':
                    skeletonHTML += `
                        <div class="skeleton-row">
                            <div class="skeleton skeleton-avatar"></div>
                            <div style="flex:1">
                                <div class="skeleton skeleton-text medium"></div>
                                <div class="skeleton skeleton-text short"></div>
                            </div>
                        </div>
                    `;
                    break;
                case 'list':
                    skeletonHTML += `
                        <div style="padding:16px;border-bottom:1px solid var(--border-color)">
                            <div class="skeleton skeleton-title"></div>
                            <div class="skeleton skeleton-text"></div>
                            <div class="skeleton skeleton-text short"></div>
                        </div>
                    `;
                    break;
            }
        }
        
        container.innerHTML = skeletonHTML;
    },
    
    // Hide skeleton and show content
    hideSkeleton(containerId) {
        const container = document.getElementById(containerId);
        if (container) {
            container.querySelectorAll('.skeleton').forEach(el => el.remove());
        }
    },
    
    // Enhanced touch feedback
    initTouchFeedback() {
        if (!this.isTouch) return;
        
        document.querySelectorAll('.btn, .card, .tab, .nav-item, .action-btn').forEach(el => {
            el.classList.add('touch-feedback');
            
            el.addEventListener('touchstart', (e) => {
                const rect = el.getBoundingClientRect();
                const x = ((e.touches[0].clientX - rect.left) / rect.width) * 100;
                const y = ((e.touches[0].clientY - rect.top) / rect.height) * 100;
                el.style.setProperty('--touch-x', `${x}%`);
                el.style.setProperty('--touch-y', `${y}%`);
            }, { passive: true });
        });
    },
    
    // Mobile Search
    showMobileSearch() {
        let searchBar = document.getElementById('mobile-search-bar');
        
        if (!searchBar) {
            searchBar = document.createElement('div');
            searchBar.id = 'mobile-search-bar';
            searchBar.className = 'mobile-search-bar';
            searchBar.innerHTML = `
                <div class="mobile-search-input-group">
                    <span class="mobile-search-icon">⌕</span>
                    <input type="text" class="mobile-search-input" placeholder="Search assets, transactions..." id="mobile-search-input">
                    <button class="mobile-search-mic" title="Voice search">◯</button>
                </div>
            `;
            
            const container = document.querySelector('.container');
            if (container) container.insertBefore(searchBar, container.firstChild);
            
            // Bind search input
            const input = searchBar.querySelector('#mobile-search-input');
            input?.addEventListener('input', (e) => {
                this.handleMobileSearch(e.target.value);
            });
        }
        
        searchBar.classList.add('visible');
        searchBar.querySelector('input')?.focus();
    },
    
    hideMobileSearch() {
        const searchBar = document.getElementById('mobile-search-bar');
        if (searchBar) searchBar.classList.remove('visible');
    },
    
    handleMobileSearch(query) {
        if (!query || query.length < 2) return;
        
        // Search across crypto, equities, transactions
        const results = [];
        
        // Search crypto
        (this.data.crypto || []).forEach(c => {
            if (c.name.toLowerCase().includes(query.toLowerCase()) || 
                c.symbol.toLowerCase().includes(query.toLowerCase())) {
                results.push({ type: 'crypto', item: c });
            }
        });
        
        // Search equities
        (this.data.equities || []).forEach(e => {
            if (e.name.toLowerCase().includes(query.toLowerCase()) || 
                e.symbol.toLowerCase().includes(query.toLowerCase())) {
                results.push({ type: 'equity', item: e });
            }
        });
        
        
        
        // Could show results in a dropdown here
    },
    
    // Number input with stepper
    createNumberStepper(inputId) {
        const input = document.getElementById(inputId);
        if (!input || input.parentElement.classList.contains('number-input-group')) return;
        
        const wrapper = document.createElement('div');
        wrapper.className = 'number-input-group';
        
        const minusBtn = document.createElement('button');
        minusBtn.type = 'button';
        minusBtn.className = 'number-stepper';
        minusBtn.textContent = '−';
        minusBtn.onclick = () => {
            const step = parseFloat(input.step) || 1;
            input.value = Math.max(parseFloat(input.min) || 0, (parseFloat(input.value) || 0) - step);
            input.dispatchEvent(new Event('input'));
        };
        
        const plusBtn = document.createElement('button');
        plusBtn.type = 'button';
        plusBtn.className = 'number-stepper';
        plusBtn.textContent = '+';
        plusBtn.onclick = () => {
            const step = parseFloat(input.step) || 1;
            const max = parseFloat(input.max) || Infinity;
            input.value = Math.min(max, (parseFloat(input.value) || 0) + step);
            input.dispatchEvent(new Event('input'));
        };
        
        input.parentElement.insertBefore(wrapper, input);
        wrapper.appendChild(minusBtn);
        wrapper.appendChild(input);
        wrapper.appendChild(plusBtn);
    }
});

